import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void typicalCaseTieInBucket() {
        // 1 freq=2, 2 freq=2, 3 freq=1; bucket[2]=[1,2] (asc); top-2: [1,2]
        int[] nums = {1, 1, 2, 2, 3};
        assertArrayEquals(new int[]{1, 2}, new Solution().topKFrequentViaBucket(nums, 2));
    }

    @Test
    void clearWinnerInHighBucket() {
        // 4 freq=3, 2 freq=2, 1 freq=1; top-1: [4]
        int[] nums = {4, 4, 4, 2, 2, 1};
        assertArrayEquals(new int[]{4}, new Solution().topKFrequentViaBucket(nums, 1));
    }

    @Test
    void tiebreakAscendingWithinBucket() {
        // 3 freq=2, 5 freq=2, 7 freq=1; bucket[2]=[3,5] (asc); top-2: [3,5]
        int[] nums = {5, 5, 3, 3, 7};
        assertArrayEquals(new int[]{3, 5}, new Solution().topKFrequentViaBucket(nums, 2));
    }

    @Test
    void kEqualsDistinctCount() {
        // k=3 equals distinct count; 2 freq=3, 1 freq=2, 9 freq=1 => [2,1,9]
        int[] nums = {2, 2, 2, 1, 1, 9};
        assertArrayEquals(new int[]{2, 1, 9}, new Solution().topKFrequentViaBucket(nums, 3));
    }

    @Test
    void kExceedsDistinctCount() {
        // k=5 but only 2 distinct values; 6 freq=2, 8 freq=1 => [6,8]
        int[] nums = {6, 6, 8};
        assertArrayEquals(new int[]{6, 8}, new Solution().topKFrequentViaBucket(nums, 5));
    }

    @Test
    void emptyInput() {
        assertArrayEquals(new int[]{}, new Solution().topKFrequentViaBucket(new int[]{}, 3));
    }

    @Test
    void allSameElement() {
        // single distinct value with freq=4; top-1: [100]
        int[] nums = {100, 100, 100, 100};
        assertArrayEquals(new int[]{100}, new Solution().topKFrequentViaBucket(nums, 1));
    }
}
